const e="ignis",t="ignis",s="Avec Ignis — La Colère",a={start:{id:"start",type:"message",speaker:"ignis",text:"Salut, moi c'est Ignis ! Je connais très bien la colère. On va lui parler ensemble.",next:"q1"},q1:{id:"q1",type:"question",speaker:"ignis",text:"Là maintenant, ton corps il ressemble à quoi ?",options:[{id:"q1_hot",label:"Chaud, serré",next:"q2_hot"},{id:"q1_explode",label:"Prêt à exploser",next:"q2_explode"},{id:"q1_shake",label:"Qui tremble",next:"q2_shake"}]},q2_hot:{id:"q2_hot",type:"message+question",speaker:"ignis",text:"Quand le corps devient chaud et serré, la colère cherche une sortie. Il faut juste lui trouver le bon passage.",question:"Qu'est-ce qui s'est passé ?",options:[{id:"q2h_no",label:"On m'a dit non",next:"q3_no"},{id:"q2h_hurt",label:"Quelqu'un m'a blessé",next:"q3_hurt"},{id:"q2h_unfair",label:"C'est pas juste",next:"q3_unfair"}]},q2_explode:{id:"q2_explode",type:"message+question",speaker:"ignis",text:"Prêt à exploser — ça veut dire que ta colère est très forte en ce moment. On va l'aider à sortir sans tout brûler.",question:"Tu veux plutôt…",options:[{id:"q2e_shout",label:"Crier",next:"reframe_shout"},{id:"q2e_move",label:"Bouger fort",next:"minigame_fire"},{id:"q2e_say",label:"Dire ce qui s'est passé",next:"q2_hot"}]},q2_shake:{id:"q2_shake",type:"message",speaker:"ignis",text:"Trembler de colère, ça arrive. Ton corps libère de l'énergie de cette façon. Ça va passer.",next:"minigame_fire"},q3_no:{id:"q3_no",type:"message",speaker:"ignis",text:"Se faire dire non, ça peut faire beaucoup de colère. Et en même temps, ça ne veut pas dire qu'on t'en veut. Les 'non' des adultes, c'est souvent pour te protéger — même quand c'est difficile à entendre.",next:"minigame_fire"},q3_hurt:{id:"q3_hurt",type:"message+question",speaker:"ignis",text:"Quand quelqu'un nous blesse, être en colère c'est normal. Ça veut dire que ça comptait pour toi.",question:"Tu veux…",options:[{id:"q3h_say",label:"Dire que ça m'a fait mal",next:"reframe_say_hurt"},{id:"q3h_move",label:"D'abord bouger pour me calmer",next:"minigame_fire"}]},q3_unfair:{id:"q3_unfair",type:"message",speaker:"ignis",text:"Quand quelque chose est vraiment injuste, la colère est une réaction normale et même utile. Elle dit 'ce n'est pas acceptable'. C'est important d'écouter ça.",next:"reframe_unfair"},reframe_shout:{id:"reframe_shout",type:"reframe",speaker:"ignis",text:"Crier dans un coussin ou seul dans ta chambre, c'est une façon de sortir la pression sans faire de mal. Après, le corps se sent souvent plus léger.",next:"minigame_fire"},reframe_say_hurt:{id:"reframe_say_hurt",type:"reframe",speaker:"ignis",text:"Dire 'ça m'a blessé quand tu as fait ça', c'est très courageux. C'est plus fort que de crier. Et souvent, ça change vraiment les choses.",next:"minigame_fire"},reframe_unfair:{id:"reframe_unfair",type:"reframe",speaker:"ignis",text:"Ressentir qu'une chose est injuste, c'est avoir du sens moral. Ça veut dire que tu sais ce qui est bien. Ta colère a raison — même si on ne peut pas toujours tout changer.",next:"minigame_fire"},minigame_fire:{id:"minigame_fire",type:"minigame",game:"FireCalm",speaker:"ignis",intro:"Tapote les braises pour calmer le feu. Chaque tapotement fait descendre la chaleur.",next:"formula_select"},formula_select:{id:"formula_select",type:"formula",entity:"ignis",next:"moral"},moral:{id:"moral",type:"moral",entity:"ignis",next:"end"},end:{id:"end",type:"end",speaker:"milo",text:"Ta colère t'appartient. Maintenant tu sais quoi en faire. Essaie dans la vraie vie.",next:null}},i={id:e,entity:t,title:s,nodes:a};export{i as default,t as entity,e as id,a as nodes,s as title};
